lidator);         // some filters require routeId         // TODO: is there a better place to apply this?         if (configuration instanceof HasRouteId) &#123;            HasRouteId hasRouteId = (HasRouteId) configuration;            hasRouteId.setRouteId(id);         &#125;         GatewayFilter gatewayFilter = factory.apply(configuration);         //asset statement start         if (configuration instanceof StripPrefixGatewayFilterFactory.Config) &#123;            int parts = ((Config) configuration).getParts();            if (StringUtils.equals(&quot;r1&quot;, id) &amp;&amp; !StringUtils.equals(&quot;1&quot;, String.valueOf(parts))) &#123;               logger.error(&quot;for router id r1,expect parts is 1,but actual is &#123;&#125;&quot;, parts);               Thread.currentThread().interrupt();            &#125; else if (StringUtils.equals(&quot;r2&quot;, id) &amp;&amp; !StringUtils                    .equals(&quot;5&quot;, String.valueOf(parts))) &#123;               logger.error(&quot;for router id r2,expect parts is 2,but actual is &#123;&#125;&quot;, parts);               Thread.currentThread().interrupt();            &#125;         &#125;         //asset statement end         if (gatewayFilter instanceof Ordered) &#123;            ordered.add(gatewayFilter);         &#125; else &#123;            ordered.add(new OrderedGatewayFilter(gatewayFilter, i + 1));         &#125;      &#125;      return ordered;   &#125;   @Override   public void setBeanFactory(BeanFactory beanFactory) throws BeansException &#123;      this.beanFactory = beanFactory;   &#125;   @Before   public void init() &#123;      gatewayFilterFactoryList.forEach(              factory -&gt; this.gatewayFilterFactories.put(factory.name(), factory));   &#125;&#125;

前言
web在部署到linux环境后，一般都是把日志等级设置加高。只输出Error信息或者直接关闭Log。但是某些系统需要搜集容器的access日志来做数据分析。如果本地存储的话，日子久了，日志就越来越大。占用大量磁盘资源，直接影响到系统的正常运行。所以，这种情况下，对日志做定期清理，是成本最低的方法了。

过程删除文件脚本find 对应目录 -mtime +天数 -name &quot;文件名&quot; -exec rm -rf &#123;&#125; \;
例如:删除3天前 &#x2F;opt&#x2F;logs下 search开头的日志。
find /opt/logs/ -mtime +3 -name &quot;search*.log&quot; exec rm -rf &#123;&#125; \;
说明：find：linux的查找命令，用户查找指定条件的文件&#x2F;opt&#x2F;logs&#x2F;：想要进行清理的任意目录；-mtime：标准语句写法；+3：查找30天前的文件，这里用数字代表天数；“search*.log”：支持范式匹配-exec：执行rm -rf：强制删除命令{} ; ：固定写法，一对大括号+空格++; 
计划任务将以上命令放置到可执行shell脚本中再通过cron调度执行。创建shell:  
touch ~/bin/auto-del-30-days-ago-log.shchmod +x auto-del-30-days-ago-log.sh
编辑shell脚本
vim auto-del-3-days-ago-log.sh
内容如下：  
#!/bin/shfind /opt/logs/ -mtime +3 -name &quot;search*.log&quot; exec rm -rf &#123;&#125; \;
添加计划调度：执行：
10 0 * * * ~/auto-del-3-days-ago-log.sh &gt;/dev/null 2&gt;&amp;1
设置是每天凌晨0点10分执行auto-del-3-days-ago-log.sh文件进行数据清理任务了。
总结THE END.

缓存设计
缓存穿透缓存穿透是指查询一个根本不存在的数据， 缓存层和存储层都不会命中， 通常出于容错的考虑， 如果从存储层查不到数据则不写入缓存层。缓存穿透将导致不存在的数据每次请求都要到存储层去查询， 失去了缓存保护后端存储的意义。
造成缓存穿透的基本原因有两个：第一， 自身业务代码或者数据出现问题。第二， 一些恶意攻击、 爬虫等造成大量空命中。缓存穿透问题解决方案：
缓存空对象String get(String key) &#123;    // 从缓存中获取数据    String cacheValue = cache.get(key);    // 缓存为空    if (StringUtils.isBlank(cacheValue)) &#123;        // 从存储中获取        String storageValue = storage.get(key);        cache.set(key, storageValue);        // 如果存储数据为空， 需要设置一个过期时间(300秒)        if (storageValue == null) &#123;            cache.expire(key, 60 * 5);        &#125;        return storageValue;    &#125; else &#123;        // 缓存非空        return cacheValue;    &#125;&#125;

布隆过滤器对于恶意攻击，向服务器请求大量不存在的数据造成的缓存穿透，还可以用布隆过滤器先做一次过滤，对于不存在的数据布隆过滤器一般都能够过滤掉，不让请求再往后端发送。当布隆过滤器说某个值存在时，这个值可能不存在；当它说不存在时，那就肯定不存在。

布隆过滤器就是一个大型的位数组和几个不一样的无偏 hash 函数。所谓无偏就是能够把元素的 hash 值算得比较均匀。向布隆过滤器中添加 key 时，会使用多个 hash 函数对 key 进行 hash 算得一个整数索引值然后对位数组长度进行取模运算得到一个位置，每个 hash 函数都会算得一个不同的位置。再把位数组的这几个位置都置为 1 就完成了 add 操作。
向布隆过滤器询问 key 是否存在时，跟 add 一样，也会把 hash 的几个位置都算出来，看看位数组中这几个位置是否都为 1，只要有一个位为 0，那么说明布隆过滤器中这个key 不存在。如果都是 1，这并不能说明这个 key 就一定存在，只是极有可能存在，因为这些位被置为 1 可能是因为其它的 key 存在所致。如果这个位数组长度比较大，存在概率就会很大，如果这个位数组长度比较小，存在概率就会降低。
这种方法适用于数据命中不高、 数据相对固定、 实时性低（通常是数据集较大） 的应用场景， 代码维护较为复杂， 但是缓存空间占用很少。可以用redisson实现布隆过滤器，引入依赖：
&lt;dependency&gt;   &lt;groupId&gt;org.redisson&lt;/groupId&gt;   &lt;artifactId&gt;redisson&lt;/artifactId&gt;   &lt;version&gt;3.6.5&lt;/version&gt;&lt;/dependency&gt;

示例伪代码：
package com.redisson;import org.redisson.Redisson;import org.redisson.api.RBloomFilter;import org.redisson.api.RedissonClient;import org.redisson.config.Config;public class RedissonBloomFilter &#123;    public static void main(String[] args) &#123;        Config config = new Config();        config.useSingleServer().setAddress(&quot;redis://localhost:6379&quot;);        //构造Redisson        RedissonClient redisson = Redisson.create(config);        RBloomFilter&lt;String&gt; bloomFilter = redisson.getBloomFilter(&quot;nameList&quot;);        //初始化布隆过滤器：预计元素为100000000L,误差率为3%,根据这两个参数会计算出底层的bit数组大小        bloomFilter.tryInit(100000000L,0.03);        //将zhuge插入到布隆过滤器中        bloomFilter.add(&quot;zhuge&quot;);        //判断下面号码是否在布隆过滤器中        System.out.println(bloomFilter.contains(&quot;guojia&quot;));//false        System.out.println(bloomFilter.contains(&quot;baiqi&quot;));//false        System.out.println(bloomFilter.contains(&quot;zhuge&quot;));//true    &#125;&#125;
使用布隆过滤器需要把所有数据提前放入布隆过滤器，并且在增加数据时也要往布隆过滤器里放，布隆过滤器缓存过滤伪代码：
//初始化布隆过滤器RBloomFilter&lt;String&gt; bloomFilter = redisson.getBloomFilter(&quot;nameList&quot;);//初始化布隆过滤器：预计元素为100000000L,误差率为3%        bloomFilter.tryInit(100000000L,0.03);//把所有数据存入布隆过滤器        void init()&#123;            for (String key: keys) &#123;                bloomFilter.put(key);            &#125;        &#125;        String get(String key) &#123;            // 从布隆过滤器这一级缓存判断下key是否存在            Boolean exist = bloomFilter.contains(key);            if(!exist)&#123;                return &quot;&quot;;            &#125;            // 从缓存中获取数据            String cacheValue = cache.get(key);            // 缓存为空            if (StringUtils.isBlank(cacheValue)) &#123;                // 从存储中获取                String storageValue = storage.get(key);                cache.set(key, storageValue);                // 如果存储数据为空， 需要设置一个过期时间(300秒)                if (storageValue == null) &#123;                    cache.expire(key, 60 * 5);                &#125;                return storageValue;            &#125; else &#123;                // 缓存非空                return cacheValue;            &#125;        &#125;

注意：布隆过滤器不能删除数据，如果要删除得重新初始化数据。
缓存失效（击穿）由于大批量缓存在同一时间失效可能导致大量请求同时穿透缓存直达数据库，可能会造成数据库瞬间压力过大甚至挂掉，对于这种情况我们在批量增加缓存时最好将这一批数据的缓存过期时间设置为一个时间段内的不同时间。示例伪代码：
String get(String key) &#123;    // 从缓存中获取数据    String cacheValue = cache.get(key);    // 缓存为空    if (StringUtils.isBlank(cacheValue)) &#123;        // 从存储中获取        String storageValue = storage.get(key);        cache.set(key, storageValue);        //设置一个过期时间(300到600之间的一个随机数)        int expireTime = new Random().nextInt(300)  + 300;        if (storageValue == null) &#123;            cache.expire(key, expireTime);        &#125;        return storageValue;    &#125; else &#123;        // 缓存非空        return cacheValue;    &#125;&#125;

缓存雪崩缓存雪崩指的是缓存层支撑不住或宕掉后， 流量会像奔逃的野牛一样， 打向后端存储层。由于缓存层承载着大量请求， 有效地保护了存储层， 但是如果缓存层由于某些原因不能提供服务(比如超大并发过来，缓存层支撑不住，或者由于缓存设计不好，类似大量请求访问bigkey，导致缓存能支撑的并发急剧下降)， 于是大量请求都会打到存储层， 存储层的调用量会暴增， 造成存储层也会级联宕机的情况。预防和解决缓存雪崩问题， 可以从以下三个方面进行着手。1） 保证缓存层服务高可用性，比如使用Redis Sentinel或Redis Cluster。2） 依赖隔离组件为后端限流熔断并降级。比如使用Sentinel或Hystrix限流降级组件。比如服务降级，我们可以针对不同的数据采取不同的处理方式。当业务应用访问的是非核心数据（例如电商商品属性，用户信息等）时，暂时停止从缓存中查询这些数据，而是直接返回预定义的默认降级信息、空值或是错误提示信息；当业务应用访问的是核心数据（例如电商商品库存）时，仍然允许查询缓存，如果缓存缺失，也可以继续通过数据库读取。3） 提前演练。 在项目上线前， 演练缓存层宕掉后， 应用以及后端的负载情况以及可能出现的问题， 在此基础上做一些预案设定。
热点缓存key重建优化开发人员使用“缓存+过期时间”的策略既可以加速数据读写， 又保证数据的定期更新， 这种模式基本能够满足绝大部分需求。 但是有两个问题如果同时出现， 可能就会对应用造成致命的危害：当前key是一个热点key（例如一个热门的娱乐新闻），并发量非常大。重建缓存不能在短时间完成， 可能是一个复杂计算， 例如复杂的SQL、 多次IO、 多个依赖等。在缓存失效的瞬间， 有大量线程来重建缓存， 造成后端负载加大， 甚至可能会让应用崩溃。要解决这个问题主要就是要避免大量线程同时重建缓存。我们可以利用互斥锁来解决，此方法只允许一个线程重建缓存， 其他线程等待重建缓存的线程执行完， 重新从缓存获取数据即可。示例伪代码：
String get(String key) &#123;    // 从Redis中获取数据    String value = redis.get(key);    // 如果value为空， 则开始重构缓存    if (value == null) &#123;        // 只允许一个线程重建缓存， 使用nx， 并设置过期时间ex        String mutexKey = &quot;mutext:key:&quot; + key;        if (redis.set(mutexKey, &quot;1&quot;, &quot;ex 180&quot;, &quot;nx&quot;)) &#123;             // 从数据源获取数据            value = db.get(key);            // 回写Redis， 并设置过期时间            redis.setex(key, timeout, value);            // 删除key_mutex            redis.delete(mutexKey);        &#125;// 其他线程休息50毫秒后重试        else &#123;            Thread.sleep(50);            get(key);        &#125;    &#125;    return value;&#125;

缓存与数据库双写不一致在大并发下，同时操作数据库与缓存会存在数据不一致性问题1、双写不一致情况2. 读写不一致
解决方案1、对于并发几率很小的数据(如个人维度的订单数据、用户数据等)，这种几乎不用考虑这个问题，很少会发生缓存不一致，可以给缓存数据加上过期时间，每隔一段时间触发读的主动更新即可。2、就算并发很高，如果业务上能容忍短时间的缓存数据不一致(如商品名称，商品分类菜单等)，缓存加上过期时间依然可以解决大部分业务对于缓存的要求。3、如果不能容忍缓存数据不一致，可以通过加分布式读写锁保证并发读写或写写的时候按顺序排好队，读读的时候相当于无锁。4、也可以用阿里开源的canal通过监听数据库的binlog日志及时的去修改缓存，但是引入了新的中间件，增加了系统的复杂度。

总结以上我们针对的都是读多写少的情况加入缓存提高性能，如果写多读多的情况又不能容忍缓存数据不一致，那就没必要加缓存了，可以直接操作数据库。当然，如果数据库抗不住压力，还可以把缓存作为数据读写的主存储，异步将数据同步到数据库，数据库只是作为数据的备份。放入缓存的数据应该是对实时性、一致性要求不是很高的数据。切记不要为了用缓存，同时又要保证绝对的一致性做大量的过度设计和控制，增加系统复杂性！

概述分布式系统，各种系统平台建设中，需要用到全局唯一的ID场景，可以统一地进行一些简单的统计和排序。这时候我们需要一个统一的ID生成系统来做这个事情。Twitter Snowflake 可以作为一个满足基础需求的原始样本算法。可以以此为蓝本开发自己的业务ID生成算法。
结构snowflake的结构如下(每部分用-分开):0 - 0000000000 0000000000 0000000000 0000000000 0 - 00000 - 00000 - 000000000000第一位为未使用，接下来的41位为毫秒级时间(41位的长度可以使用69年)，然后是5位datacenterId和5位workerId(10位的长度最多支持部署1024个节点） ，最后12位是毫秒内的计数（12位的计数顺序号支持每个节点每毫秒产生4096个ID序号）一共加起来刚好64位，为一个Long型。(转换成字符串后长度最多19)snowflake生成的ID整体上按照时间自增排序，并且整个分布式系统内不会产生ID碰撞（由datacenter和workerId作区分），并且效率较高。经测试snowflake每秒能够产生26万个ID。
Java实现/** * Twitter_Snowflake&lt;br&gt; * SnowFlake的结构如下(每部分用-分开):&lt;br&gt; * 0 - 0000000000 0000000000 0000000000 0000000000 0 - 00000 - 00000 - 000000000000 &lt;br&gt; * 1位标识，由于long基本类型在Java中是带符号的，最高位是符号位，正数是0，负数是1，所以id一般是正数，最高位是0&lt;br&gt; * 41位时间截(毫秒级)，注意，41位时间截不是存储当前时间的时间截，而是存储时间截的差值（当前时间截 - 开始时间截) * 得到的值），这里的的开始时间截，一般是我们的id生成器开始使用的时间，由我们程序来指定的（如下下面程序IdWorker类的startTime属性）。41位的时间截，可以使用69年，年T = (1L &lt;&lt; 41) / (1000L * 60 * 60 * 24 * 365) = 69&lt;br&gt; * 10位的数据机器位，可以部署在1024个节点，包括5位datacenterId和5位workerId&lt;br&gt; * 12位序列，毫秒内的计数，12位的计数顺序号支持每个节点每毫秒(同一机器，同一时间截)产生4096个ID序号&lt;br&gt; * 加起来刚好64位，为一个Long型。&lt;br&gt; * SnowFlake的优点是，整体上按照时间自增排序，并且整个分布式系统内不会产生ID碰撞(由数据中心ID和机器ID作区分)，并且效率较高，经测试，SnowFlake每秒能够产生26万ID左右。 */public class SnowflakeIdWorker &#123;    // ==============================Fields===========================================    /** 开始时间截 (2015-01-01) */    private final long twepoch = 1420041600000L;    /** 机器id所占的位数 */    private final long workerIdBits = 5L;    /** 数据标识id所占的位数 */    private final long datacenterIdBits = 5L;    /** 支持的最大机器id，结果是31 (这个移位算法可以很快的计算出几位二进制数所能表示的最大十进制数) */    private final long maxWorkerId = -1L ^ (-1L &lt;&lt; workerIdBits);    /** 支持的最大数据标识id，结果是31 */    private final long maxDatacenterId = -1L ^ (-1L &lt;&lt; datacenterIdBits);    /** 序列在id中占的位数 */    private final long sequenceBits = 12L;    /** 机器ID向左移12位 */    private final long workerIdShift = sequenceBits;    /** 数据标识id向左移17位(12+5) */    private final long datacenterIdShift = sequenceBits + workerIdBits;    /** 时间截向左移22位(5+5+12) */    private final long timestampLeftShift = sequenceBits + workerIdBits + datacenterIdBits;    /** 生成序列的掩码，这里为4095 (0b111111111111=0xfff=4095) */    private final long sequenceMask = -1L ^ (-1L &lt;&lt; sequenceBits);    /** 工作机器ID(0~31) */    private long workerId;    /** 数据中心ID(0~31) */    private long datacenterId;    /** 毫秒内序列(0~4095) */    private long sequence = 0L;    /** 上次生成ID的时间截 */    private long lastTimestamp = -1L;    //==============================Constructors=====================================    /**     * 构造函数     * @param workerId 工作ID (0~31)     * @param datacenterId 数据中心ID (0~31)     */    public SnowflakeIdWorker(long workerId, long datacenterId) &#123;        if (workerId &gt; maxWorkerId || workerId &lt; 0) &#123;            throw new IllegalArgumentException(String.format(&quot;worker Id can&#x27;t be greater than %d or less than 0&quot;, maxWorkerId));        &#125;        if (datacenterId &gt; maxDatacenterId || datacenterId &lt; 0) &#123;            throw new IllegalArgumentException(String.format(&quot;datacenter Id can&#x27;t be greater than %d or less than 0&quot;, maxDatacenterId));        &#125;        this.workerId = workerId;        this.datacenterId = datacenterId;    &#125;    // ==============================Methods==========================================    /**     * 获得下一个ID (该方法是线程安全的)     * @return SnowflakeId     */    public synchronized long nextId() &#123;        long timestamp = timeGen();        //如果当前时间小于上一次ID生成的时间戳，说明系统时钟回退过这个时候应当抛出异常        if (timestamp &lt; lastTimestamp) &#123;            throw new RuntimeException(                    String.format(&quot;Clock moved backwards.  Refusing to generate id for %d milliseconds&quot;, lastTimestamp - timestamp));        &#125;        //如果是同一时间生成的，则进行毫秒内序列        if (lastTimestamp == timestamp) &#123;            sequence = (sequence + 1) &amp; sequenceMask;            //毫秒内序列溢出            if (sequence == 0) &#123;                //阻塞到下一个毫秒,获得新的时间戳                timestamp = tilNextMillis(lastTimestamp);            &#125;        &#125;        //时间戳改变，毫秒内序列重置        else &#123;            sequence = 0L;        &#125;        //上次生成ID的时间截        lastTimestamp = timestamp;        //移位并通过或运算拼到一起组成64位的ID        return ((timestamp - twepoch) &lt;&lt; timestampLeftShift) //                | (datacenterId &lt;&lt; datacenterIdShift) //                | (workerId &lt;&lt; workerIdShift) //                | sequence;    &#125;    /**     * 阻塞到下一个毫秒，直到获得新的时间戳     * @param lastTimestamp 上次生成ID的时间截     * @return 当前时间戳     */    protected long tilNextMillis(long lastTimestamp) &#123;        long timestamp = timeGen();        while (timestamp &lt;= lastTimestamp) &#123;            timestamp = timeGen();        &#125;        return timestamp;    &#125;    /**     * 返回以毫秒为单位的当前时间     * @return 当前时间(毫秒)     */    protected long timeGen() &#123;        return System.currentTimeMillis();    &#125;    //==============================Test=============================================    /** 测试 */    public static void main(String[] args) &#123;        SnowflakeIdWorker idWorker = new SnowflakeIdWorker(0, 0);        for (int i = 0; i &lt; 1000; i++) &#123;            long id = idWorker.nextId();            System.out.println(Long.toBinaryString(id));            System.out.println(id);        &#125;    &#125;&#125;

